/* mruby driver for the wasdon-zig WASI benchmark.
 *
 * Compiled by the local Makefile against the wasi-sdk clang toolchain
 * and statically linked against a vendored mruby (mruby/mruby pinned
 * via MRUBY_TAG).
 *
 * The benchmark Ruby script (bench.rb) is precompiled into mruby IREP
 * bytecode and embedded in this binary as a C array (`bench_irep`),
 * generated by `mrbc -B bench_irep -o bench.c bench.rb`. That avoids
 * any filesystem dependency at runtime, which keeps the WASI surface
 * inside the subset wasdon-zig supports (see
 * docs/spec_wasi_preview_1.md §2.1).
 *
 * Wall-time measurement uses `clock_gettime(CLOCK_MONOTONIC)` →
 * wasi-libc → `clock_time_get`(monotonic). Output goes through `printf`
 * → `fd_write`. Exit is the natural _start return.
 */

#include <stdint.h>
#include <stdio.h>
#include <time.h>

#include <mruby.h>
#include <mruby/irep.h>

extern const uint8_t bench_irep[];

static double timespec_diff_ms(const struct timespec *a, const struct timespec *b) {
    double sec = (double)(b->tv_sec - a->tv_sec);
    double nsec = (double)(b->tv_nsec - a->tv_nsec);
    return sec * 1000.0 + nsec / 1.0e6;
}

int main(void) {
    mrb_state *mrb = mrb_open();
    if (mrb == NULL) {
        fprintf(stderr, "mrb_open failed\n");
        return 1;
    }

    struct timespec t0, t1;
    clock_gettime(CLOCK_MONOTONIC, &t0);
    mrb_load_irep(mrb, bench_irep);
    clock_gettime(CLOCK_MONOTONIC, &t1);

    if (mrb->exc) {
        fprintf(stderr, "mruby raised an exception\n");
        mrb_close(mrb);
        return 1;
    }

    printf("elapsed = %.2f ms\n", timespec_diff_ms(&t0, &t1));

    mrb_close(mrb);
    return 0;
}
